import {
  forwardRef,
  type ReactNode,
  useImperativeHandle,
  useRef,
  useState,
} from 'react';

import type { ComponentWithName } from '../../../../../core/types/component-with-name.js';
import { MeterBarChartToolbar } from '../../meter-bar-toolbar/MeterBarToolbar.js';
import { useComputedSegmentSize } from '../hooks/useComputedSegmentSize.js';
import {
  toolbarAnimatedContainer,
  valueAnimatedContainer,
  valueContainer,
} from '../MeterBarLayout.sty.js';

interface TopRightSlotProps {
  value: ReactNode;
  isToolbarEnabled: boolean;
}

interface TopRightSlotRef {
  showPopover: () => void;
  hidePopover: () => void;
}

const toolbarWidth = '24px';
const toolbarMarginLeft = '4px';

export const MeterBarLayoutTopRightSlot = forwardRef<
  TopRightSlotRef,
  TopRightSlotProps
>(({ isToolbarEnabled, value }, forwardedRef) => {
  const [isChartHovered, setIsChartHovered] = useState(false);
  const popoverRef = useRef<HTMLDivElement | null>(null);
  const { valueLabelRef } = useComputedSegmentSize();
  const showPopover = () => setIsChartHovered(true);
  const hidePopover = () => setIsChartHovered(false);
  useImperativeHandle(forwardedRef, () => ({
    showPopover,
    hidePopover,
  }));
  const isToolbarShown = isChartHovered && isToolbarEnabled;

  return (
    <div
      ref={valueLabelRef}
      className={valueContainer({ inline: isToolbarEnabled })}
    >
      {value && <div className={valueAnimatedContainer}>{value}</div>}
      {isToolbarEnabled && (
        <div
          ref={popoverRef}
          className={toolbarAnimatedContainer}
          style={{
            width: isToolbarShown ? toolbarWidth : 0,
            opacity: isToolbarShown ? 1 : 0,
            marginLeft: isToolbarShown ? toolbarMarginLeft : 0,
          }}
        >
          <MeterBarChartToolbar />
        </div>
      )}
    </div>
  );
});

(
  MeterBarLayoutTopRightSlot as ComponentWithName<
    typeof MeterBarLayoutTopRightSlot
  >
).displayName = 'MeterBarLayoutTopRightSlot';
